            AddBits(ZopfliGetDistExtraBitsValue(dist),
                    ZopfliGetDistExtraBits(dist),
                    bp, out, outsize);
            testlength += litlen;
        }
    }
    assert(expected_data_size == 0 || testlength == expected_data_size);
